{"type":"freeform","cover":{"titleText":"","subTitleText":"","presenterText":"","dateText":"","logos":[]},"section":{"sectionText":"","smallerSectionText":""},"freeform":{"content":[[{"type":"text","stretch":true,"fillArea":true,"textSize":1,"textBackground":"grey","placeholderInvisible":false,"useFigureAdditionalScale":false,"figureAdditionalScale":1,"span":3,"markdown":"Les accouchements en formation sanitaire ont atteint un excédent d’environ 9 % en mars 2025 (~56 000 contre ~51 000 attendus).
